sys_script.script:
var notificationUtil = new InsuranceNotificationUtils();

// Send notifications for renewal status changes
if (current.renewal_status.changes() || current.isNewRecord()) {
    var status = current.getValue('renewal_status');
    var clientRef = current.getValue('client_reference');

    // Send notification to client
    notificationUtil.sendRenewalNotification(current);

    // Add info message for different statuses
    switch (status) {
        case 'approved':
            gs.addInfoMessage('Renewal approved and client notified.');
            break;
        case 'rejected':
            gs.addInfoMessage('Renewal rejected. Client notification sent.');
            break;
        case 'processed':
            gs.addInfoMessage('Renewal processing complete.');
            // Auto-update the original policy record
            if (!gs.nil(clientRef)) {
                var policyGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
                if (policyGR.get(clientRef)) {
                    policyGR.setValue('premium_amount', current.getValue('new_premium'));
                    var newStartDate = current.getValue('renewal_date');
                    policyGR.setValue('policy_start_date', newStartDate);
                    // Policy end date will be recalculated by the policy business rule
                    policyGR.setValue('policy_end_date', '');
                    policyGR.update();

                    gs.addInfoMessage('Policy updated with new renewal terms.');
                }
            }
            break;
    }
}

// Set notification sent flag
if (!current.notification_sent && current.getValue('renewal_status') != 'pending') {
    current.setValue('notification_sent', true);
}
